function calculate({ dataPointsAvailable, updateFrequencyScore, dataFormatScore, historicalDataCoverage, costOfAccessScore, usabilityScore, feedbackMechanismScore, dataAccuracyVerificationScore }) {

  // Normalize 'dataPointsAvailable' to a 0-5 scale. Capped at 20 categories for max score.
  const normalizedDataPointsScore = Math.min(dataPointsAvailable / 4, 5); 

  // Normalize 'historicalDataCoverage' to a 0-5 scale. Capped at 50 years for max score.
  const normalizedHistoricalDataScore = Math.min(historicalDataCoverage / 10, 5);

  // Define weights for each transparency dimension. Total weights sum to 1.0.
  const weights = {
    dataPoints: 0.20,
    updateFrequency: 0.15,
    dataFormat: 0.15,
    historicalData: 0.10,
    costOfAccess: 0.15,
    usability: 0.10,
    feedbackMechanism: 0.075,
    dataAccuracy: 0.075
  };

  // Calculate weighted scores for each input
  const weightedScores = {
    dataPoints: normalizedDataPointsScore * weights.dataPoints,
    updateFrequency: updateFrequencyScore * weights.updateFrequency,
    dataFormat: dataFormatScore * weights.dataFormat,
    historicalData: normalizedHistoricalDataScore * weights.historicalData,
    costOfAccess: costOfAccessScore * weights.costOfAccess,
    usability: usabilityScore * weights.usability,
    feedbackMechanism: feedbackMechanismScore * weights.feedbackMechanism,
    dataAccuracy: dataAccuracyVerificationScore * weights.dataAccuracy
  };

  // Sum all weighted scores to get a raw transparency score (max 5)
  const rawTransparencyScore = Object.values(weightedScores).reduce((sum, score) => sum + score, 0);

  // Scale the raw score to a 0-100 index
  let legalDataTransparencyIndex = rawTransparencyScore * 20;

  // Ensure the index is within 0-100 range, handling potential floating point inaccuracies or edge cases.
  legalDataTransparencyIndex = Math.max(0, Math.min(100, legalDataTransparencyIndex));

  let transparencyLevel;
  if (legalDataTransparencyIndex >= 85) {
    transparencyLevel = 'Exemplary Transparency';
  } else if (legalDataTransparencyIndex >= 70) {
    transparencyLevel = 'High Transparency';
  } else if (legalDataTransparencyIndex >= 50) {
    transparencyLevel = 'Moderate Transparency';
  } else if (legalDataTransparencyIndex >= 25) {
    transparencyLevel = 'Low Transparency';
  } else {
    transparencyLevel = 'Very Low Transparency';
  }

  return {
    legalDataTransparencyIndex: legalDataTransparencyIndex,
    transparencyLevel: transparencyLevel
  };
}
